import React from "react";
import ManagerLayout from "../../components/ManagerLayout";

function EmployeeAssetsPage() {
  return (
    <ManagerLayout title="Assets" mode="self">
      <div className="manager-card">
        <h3>Assets</h3>
        <div className="empty-box">No assets available</div>
      </div>
    </ManagerLayout>
  );
}

export default EmployeeAssetsPage;
